@app.route("/api/reports/tb/insights", methods=["POST"])
@login_required
def api_tb_insights():
    """Async AI insights for TB report - called after Python report is shown"""
    
    business = Auth.get_current_business()
    biz_name = business.get("name", "Business") if business else "Business"
    
    try:
        # Try POST body first (reliable, works with gunicorn multi-worker)
        posted = request.get_json() or {}
        if posted.get('insights_payload'):
            td = posted['insights_payload']
            logger.info(f"[TB INSIGHTS] Using data from POST body")
        else:
            # Fallback to cache (legacy)
            _tb_cache_key = f"tb_insights:{session.get('user_id', 'anon')}"
            _cached = Auth._mem.get(_tb_cache_key)
            if not _cached or (time.time() - _cached.get("t", 0)) > 600:
                return jsonify({"success": False, "error": "No TB data found. Please re-analyze."})
            td = _cached["d"]
            logger.info(f"[TB INSIGHTS] Using data from cache")
        
        lang = td.get('lang', 'en')
        report_company = td.get('report_company', biz_name)
        industry = td.get('industry', 'general')
        is_third_party = td.get('is_third_party', False)
        accounts_text = td.get('accounts_text', '')
        
        total_debit = td.get('total_debit', 0)
        total_credit = td.get('total_credit', 0)
        difference = td.get('difference', 0)
        is_balanced = td.get('is_balanced', True)
        current_assets = td.get('current_assets', 0)
        bank_cash = td.get('bank_cash', 0)
        debtors = td.get('debtors', 0)
        stock = td.get('stock', 0)
        fixed_assets_net = td.get('fixed_assets_net', 0)
        total_assets = td.get('total_assets', 0)
        current_liabilities = td.get('current_liabilities', 0)
        long_term_liabilities = td.get('long_term_liabilities', 0)
        total_equity = td.get('total_equity', 0)
        net_sales = td.get('net_sales', 0)
        cos = td.get('cos', 0)
        gross_profit = td.get('gross_profit', 0)
        gp_margin = td.get('gp_margin', 0)
        total_expenses = td.get('total_expenses', 0)
        net_profit = td.get('net_profit', 0)
        np_margin = td.get('np_margin', 0)
        current_ratio = td.get('current_ratio', 0)
        quick_ratio = td.get('quick_ratio', 0)
        debt_equity = td.get('debt_equity', 0)
        debtor_days = td.get('debtor_days', 0)
        creditor_days = td.get('creditor_days', 0)
        stock_days = td.get('stock_days', 0)
        vat_position = td.get('vat_position', 0)
        paye = td.get('paye', 0)
        uif = td.get('uif', 0)
        
        if lang == "af":
            tp_note = f"\nDit is 'n DERDE PARTY kliënt se TB, nie {biz_name} s'n nie.\n" if is_third_party else ""
            insights_prompt = f"""Jy is Zane, ClickAI. Analiseer hierdie proefbalans BONDIG.

BESIGHEID: {safe_string(report_company)} | INDUSTRIE: {industry}
{tp_note}
{accounts_text}

PYTHON-BEREKENDE OPSOMMING (100% akkuraat):
- Debits: R{total_debit:,.2f} | Kredits: R{total_credit:,.2f} | {'GEBALANSEER' if is_balanced else 'ONGEBALANSEER'}
- Bates: R{total_assets:,.2f} (Bedryf R{current_assets:,.2f}, Vas R{fixed_assets_net:,.2f})
- Laste: R{current_liabilities + long_term_liabilities:,.2f} | Ekwiteit: R{total_equity:,.2f}
- Verkope: R{net_sales:,.2f} | Bruto Wins: R{gross_profit:,.2f} ({gp_margin}%) | Netto: R{net_profit:,.2f} ({np_margin}%)
- Current Ratio: {current_ratio:.2f} | Quick: {quick_ratio:.2f} | Skuld/Ekwiteit: {debt_equity:.2f}
- Debiteure Dae: {debtor_days:.0f} | Krediteure Dae: {creditor_days:.0f} | Voorraad Dae: {stock_days:.0f}
- BTW: R{abs(vat_position):,.2f} {'BETAALBAAR' if vat_position > 0 else 'TERUG'} | LBS+WVF: R{paye + uif:,.2f}

SKRYF 'N VOLLEDIGE FINANSIËLE ANALISE IN AFRIKAANS (1200-1800 woorde):
1. UITVOERENDE OPSOMMING (3-4 sinne)
2. HOOFSAKE - Sterkpunte en Swakpunte (noem spesifieke rekeninge en bedrae)
3. ROOI VLAE (net werklike probleme)
4. TOP 5 AANBEVELINGS (konkreet, met prioriteit)
5. VRAE VIR DIE KLIËNT (3-5 vrae)

REËLS: Gebruik Python syfers. Moenie kodes bevraagteken nie. Skryf skoon HTML met <h3> vir opskrifte. Voltooi AL 5 afdelings VOLLEDIG. MOENIE style="background:white" of enige ligte agtergrondkleure gebruik nie — die UI het 'n donker tema. Eindig met: Zane, ClickAI."""
        else:
            tp_note = f"\nThis is a THIRD-PARTY client TB, not {biz_name}'s data.\n" if is_third_party else ""
            insights_prompt = f"""You are Zane, ClickAI. Analyze this trial balance CONCISELY.

BUSINESS: {safe_string(report_company)} | INDUSTRY: {industry}
{tp_note}
{accounts_text}

PYTHON-CALCULATED SUMMARY (100% accurate):
- Debits: R{total_debit:,.2f} | Credits: R{total_credit:,.2f} | {'BALANCED' if is_balanced else 'UNBALANCED'}
- Assets: R{total_assets:,.2f} (Current R{current_assets:,.2f}, Fixed R{fixed_assets_net:,.2f})
- Liabilities: R{current_liabilities + long_term_liabilities:,.2f} | Equity: R{total_equity:,.2f}
- Sales: R{net_sales:,.2f} | Gross Profit: R{gross_profit:,.2f} ({gp_margin}%) | Net: R{net_profit:,.2f} ({np_margin}%)
- Current Ratio: {current_ratio:.2f} | Quick: {quick_ratio:.2f} | Debt/Equity: {debt_equity:.2f}
- Debtor Days: {debtor_days:.0f} | Creditor Days: {creditor_days:.0f} | Stock Days: {stock_days:.0f}
- VAT: R{abs(vat_position):,.2f} {'PAYABLE' if vat_position > 0 else 'REFUND'} | PAYE+UIF: R{paye + uif:,.2f}

WRITE A COMPLETE FINANCIAL ANALYSIS (1200-1800 words):
1. EXECUTIVE SUMMARY (3-4 sentences)
2. KEY FINDINGS - Strengths and Weaknesses (name specific accounts and amounts)
3. RED FLAGS (only real problems)
4. TOP 5 RECOMMENDATIONS (concrete, prioritized)
5. QUESTIONS FOR THE CLIENT (3-5 questions)

RULES: Use EXACT Python figures. Don't question account codes. Write clean HTML with <h3> for headings. Complete ALL 5 sections FULLY. Do NOT use style="background:white" or any light background colors — the UI uses a dark theme. End with sign-off: Zane, ClickAI."""
        
        if not ANTHROPIC_API_KEY:
            return jsonify({"success": False, "error": "No API key"})
        
        logger.info(f"[TB INSIGHTS] Starting async AI analysis for {report_company}")
        
        client = _anthropic_client
        message = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=12000,
            messages=[{"role": "user", "content": insights_prompt}]
        )
        
        # Log truncation
        if message.stop_reason == "max_tokens":
            logger.warning(f"[TB INSIGHTS] ⚠️ TRUNCATED — hit max_tokens")
        
        if message.content and message.content[0].text:
            insights_html = message.content[0].text
            
            import re as _re
            # Strip any raw HTML tags Sonnet might have added
            insights_html = _re.sub(r'</?html[^>]*>', '', insights_html)
            insights_html = _re.sub(r'</?body[^>]*>', '', insights_html)
            
            # Headings — purple for main, green for sub
            insights_html = _re.sub(r'^### (.+)$', r'<h3 style="color:#a78bfa;margin:22px 0 10px 0;font-size:15px;font-weight:600;">\1</h3>', insights_html, flags=_re.MULTILINE)
            insights_html = _re.sub(r'^## (.+)$', r'<h3 style="color:#10b981;border-bottom:1px solid rgba(16,185,129,0.2);padding-bottom:6px;margin:26px 0 12px 0;font-size:16px;font-weight:600;">\1</h3>', insights_html, flags=_re.MULTILINE)
            insights_html = _re.sub(r'^# (.+)$', r'<h2 style="color:#8b5cf6;border-bottom:2px solid rgba(139,92,246,0.3);padding-bottom:8px;margin:28px 0 14px 0;font-size:18px;font-weight:700;">\1</h2>', insights_html, flags=_re.MULTILINE)
            
            # Bold text — accent purple
            insights_html = _re.sub(r'\*\*(.+?)\*\*', r'<strong style="color:#a78bfa;">\1</strong>', insights_html)
            
            # Numbered items — with subtle left border
            insights_html = _re.sub(r'^\d+\. (.+)$', r'<div style="margin:8px 0 8px 12px;padding:4px 0 4px 12px;border-left:2px solid rgba(139,92,246,0.3);">→ \1</div>', insights_html, flags=_re.MULTILINE)
            
            # Bullet items
            insights_html = _re.sub(r'^- (.+)$', r'<div style="margin:6px 0 6px 12px;padding:2px 0;">• \1</div>', insights_html, flags=_re.MULTILINE)
            
            # Horizontal rules
            insights_html = _re.sub(r'^---+$', r'<hr style="border:none;border-top:1px solid rgba(255,255,255,0.08);margin:18px 0;">', insights_html, flags=_re.MULTILINE)
            
            # Paragraph spacing
            insights_html = _re.sub(r'\n{3,}', '<br><br>', insights_html)
            insights_html = _re.sub(r'\n\n', '<br><br>', insights_html)
            insights_html = _re.sub(r'(?<!>)\n(?!<)', '<br>', insights_html)
            
            # Wrap any Sonnet-generated tables in dark styling
            insights_html = insights_html.replace('<table', '<table style="width:100%;border-collapse:collapse;margin:12px 0;font-size:13px;" ')
            insights_html = insights_html.replace('<th', '<th style="padding:8px;text-align:left;border-bottom:1px solid rgba(255,255,255,0.15);color:#a78bfa;font-weight:600;" ')
            insights_html = insights_html.replace('<td', '<td style="padding:6px 8px;border-bottom:1px solid rgba(255,255,255,0.06);" ')
            
            # CRITICAL: Strip ALL white/light backgrounds Sonnet may inject
            insights_html = _re.sub(r'background[-\w]*:\s*#?(?:fff|ffffff|white|fafafa|f5f5f5|f8f8f8|f9f9f9|fef[0-9a-f]+|ffe[0-9a-f]+|fdf[0-9a-f]+)[^;"]*;?', '', insights_html, flags=_re.IGNORECASE)
            insights_html = _re.sub(r'background[-\w]*:\s*rgb\(\s*2[45]\d\s*,\s*2[45]\d\s*,\s*2[45]\d\s*\)[^;"]*;?', '', insights_html, flags=_re.IGNORECASE)
            insights_html = _re.sub(r'background[-\w]*:\s*white[^;"]*;?', '', insights_html, flags=_re.IGNORECASE)
            
            # Force text color on any divs/spans Sonnet creates
            insights_html = _re.sub(r'color:\s*#?(?:000|000000|333|333333|222|444|555|666)[^;"]*;?', 'color:rgba(255,255,255,0.9);', insights_html, flags=_re.IGNORECASE)
            insights_html = _re.sub(r'color:\s*black[^;"]*;?', 'color:rgba(255,255,255,0.9);', insights_html, flags=_re.IGNORECASE)
            insights_html = _re.sub(r'color:\s*rgb\(\s*0\s*,\s*0\s*,\s*0\s*\)[^;"]*;?', 'color:rgba(255,255,255,0.9);', insights_html, flags=_re.IGNORECASE)
            
            # Strip border colors that are dark (they become invisible on dark bg)
            insights_html = _re.sub(r'border[-\w]*:\s*\d+px\s+solid\s+#?(?:ccc|ddd|eee|e0e0e0|d0d0d0)[^;"]*;?', 'border:1px solid rgba(255,255,255,0.1);', insights_html, flags=_re.IGNORECASE)
            
            # Style the Zane sign-off if present
            insights_html = _re.sub(
                r'(Zane,?\s*ClickAI)',
                r'<div style="margin-top:20px;padding-top:12px;border-top:1px solid rgba(139,92,246,0.2);color:#8b5cf6;font-weight:600;font-style:italic;">\1</div>',
                insights_html
            )
            
            logger.info(f"[TB INSIGHTS] AI analysis complete: {len(insights_html)} chars")
            return jsonify({"success": True, "insights": insights_html})
        else:
            return jsonify({"success": False, "error": "AI returned empty"})
            
    except Exception as e:
        logger.warning(f"[TB INSIGHTS] Failed: {e}")
        return jsonify({"success": False, "error": str(e)[:200]})


# ═══════════════════════════════════════════════════════════════
# UNIVERSAL REPORT Q&A — Ask Zane about ANY report
# ═══════════════════════════════════════════════════════════════

@app.route("/api/reports/qa", methods=["POST"])
@app.route("/api/reports/tb/qa", methods=["POST"])
@login_required
def api_reports_qa():
    """
    Universal report Q&A — Ask Zane follow-up questions about any report.
    Supports: TB, P&L, Balance Sheet, Cash Flow, VAT, Aging, etc.
    
    POST body:
    {
        "question": "My 2 properties aren't on the books, how would that change the picture?",
        "report_type": "tb" | "pnl" | "balance_sheet" | "cashflow" | "vat" | "aging",
        "report_data": { ... summary numbers from the frontend ... },
        "insights_payload": { ... optional, for TB backward compat ... },
        "history": [ {role, content}, ... ],
        "lang": "en" | "af"
    }
    """
    
    business = Auth.get_current_business()
    biz_name = business.get("name", "Business") if business else "Business"
    user = Auth.get_current_user()
    user_name = user.get("name", "User") if user else "User"
    
    try:
        posted = request.get_json() or {}
        question = (posted.get("question") or "").strip()
        if not question:
            return jsonify({"success": False, "error": "No question provided"})
        
        report_type = posted.get("report_type", "tb")
        report_data = posted.get("report_data") or posted.get("insights_payload") or {}
        history = posted.get("history") or []
        lang = posted.get("lang", "en")
        
        # ─── Build report context summary ───
        report_context = ""
        
        if report_type == "tb" and report_data:
            # Trial Balance — use the full insights payload
            report_context = f"""TRIAL BALANCE SUMMARY:
- Debits: R{report_data.get('total_debit', 0):,.2f} | Credits: R{report_data.get('total_credit', 0):,.2f}
- Assets: R{report_data.get('total_assets', 0):,.2f} (Current R{report_data.get('current_assets', 0):,.2f}, Fixed R{report_data.get('fixed_assets_net', 0):,.2f})
- Bank/Cash: R{report_data.get('bank_cash', 0):,.2f} | Debtors: R{report_data.get('debtors', 0):,.2f} | Stock: R{report_data.get('stock', 0):,.2f}
- Liabilities: R{report_data.get('current_liabilities', 0) + report_data.get('long_term_liabilities', 0):,.2f} | Equity: R{report_data.get('total_equity', 0):,.2f}
- Sales: R{report_data.get('net_sales', 0):,.2f} | GP: R{report_data.get('gross_profit', 0):,.2f} ({report_data.get('gp_margin', 0)}%) | Net: R{report_data.get('net_profit', 0):,.2f} ({report_data.get('np_margin', 0)}%)
- Current Ratio: {report_data.get('current_ratio', 0):.2f} | Quick: {report_data.get('quick_ratio', 0):.2f} | Debt/Equity: {report_data.get('debt_equity', 0):.2f}
- Debtor Days: {report_data.get('debtor_days', 0):.0f} | Creditor Days: {report_data.get('creditor_days', 0):.0f} | Stock Days: {report_data.get('stock_days', 0):.0f}
- VAT: R{abs(report_data.get('vat_position', 0)):,.2f} {'PAYABLE' if report_data.get('vat_position', 0) > 0 else 'REFUND'}"""
            if report_data.get('accounts_text'):
                acct_text = str(report_data.get('accounts_text', ''))
                if len(acct_text) > 3000:
                    acct_text = acct_text[:3000] + "\n... (truncated)"
                report_context += f"\n\nDETAILED ACCOUNTS:\n{acct_text}"
        
        elif report_type == "pnl" and report_data:
            report_context = f"""INCOME STATEMENT (P&L) SUMMARY:
- Period: {report_data.get('period_label', 'Current')}
- Revenue: R{report_data.get('total_revenue', 0):,.2f} (Invoices: R{report_data.get('invoice_income', 0):,.2f}, Cash/POS: R{report_data.get('sales_income', 0):,.2f})
- Cost of Sales: R{report_data.get('cost_of_sales', 0):,.2f}
- Gross Profit: R{report_data.get('gross_profit', 0):,.2f} ({report_data.get('gross_margin', 0):.1f}%)
- Total Expenses: R{report_data.get('total_expenses', 0):,.2f}
- Net Profit: R{report_data.get('net_profit', 0):,.2f} ({report_data.get('net_margin', 0):.1f}%)"""
            if report_data.get('expense_breakdown'):
                report_context += "\n- Expense Breakdown: " + str(report_data.get('expense_breakdown', ''))
        
        elif report_type == "balance_sheet" and report_data:
            report_context = f"""BALANCE SHEET SUMMARY:
- Bank: R{report_data.get('bank_balance', 0):,.2f}
- Debtors: R{report_data.get('total_debtors', 0):,.2f}
- Stock: R{report_data.get('stock_value', 0):,.2f}
- VAT Receivable: R{report_data.get('vat_receivable', 0):,.2f}
- Total Current Assets: R{report_data.get('total_current_assets', 0):,.2f}
- Total Assets: R{report_data.get('total_assets', 0):,.2f}
- Creditors: R{report_data.get('total_creditors', 0):,.2f}
- VAT Payable: R{report_data.get('vat_payable', 0):,.2f}
- Total Liabilities: R{report_data.get('total_liabilities', 0):,.2f}
- Retained Earnings: R{report_data.get('retained_earnings', 0):,.2f}
- Total Equity: R{report_data.get('total_equity', 0):,.2f}
- Balanced: {'YES' if report_data.get('is_balanced') else 'NO (diff: R' + str(report_data.get('balance_diff', 0)) + ')'}"""
        
        elif report_type == "cashflow" and report_data:
            report_context = f"""CASH FLOW STATEMENT SUMMARY:
- Period: {report_data.get('period_label', 'Current')}
- Cash from Debtors: R{report_data.get('cash_from_debtors', 0):,.2f}
- Cash Sales: R{report_data.get('cash_sales', 0):,.2f}
- Card Sales: R{report_data.get('card_sales', 0):,.2f}
- Total Cash In: R{report_data.get('total_cash_in', 0):,.2f}
- Payments to Suppliers: R{report_data.get('cash_to_creditors', 0):,.2f}
- Operating Expenses: R{report_data.get('cash_to_expenses', 0):,.2f}
- Salaries: R{report_data.get('cash_to_employees', 0):,.2f}
- Total Cash Out: R{report_data.get('total_cash_out', 0):,.2f}
- Net Operating Cash: R{report_data.get('net_operating', 0):,.2f}"""
        
        elif report_type == "vat" and report_data:
            report_context = f"""VAT REPORT SUMMARY:
- Period: {report_data.get('period_label', 'Current')}
- Output VAT (Sales): R{report_data.get('output_vat', 0):,.2f}
- Input VAT (Purchases): R{report_data.get('input_vat', 0):,.2f}
- Net VAT: R{report_data.get('net_vat', 0):,.2f} {'PAYABLE' if report_data.get('net_vat', 0) > 0 else 'REFUND'}"""
        
        elif report_type == "aging" and report_data:
            report_context = f"""AGING REPORT SUMMARY:
- Total Outstanding: R{report_data.get('total_outstanding', 0):,.2f}
- Current (0-30 days): R{report_data.get('current', 0):,.2f}
- 30-60 days: R{report_data.get('days_30', 0):,.2f}
- 60-90 days: R{report_data.get('days_60', 0):,.2f}
- 90+ days: R{report_data.get('days_90', 0):,.2f}"""
        
        else:
            # Generic — just pass whatever data we got
            if report_data:
                report_context = f"REPORT DATA:\n{json.dumps(report_data, indent=2, default=str)[:3000]}"
            else:
                report_context = "No report data available — answer from general financial knowledge."
        
        # ─── Inject financial advisor RAG knowledge ───
        fa_knowledge = ""
        if FINANCIAL_ADVISOR_KNOWLEDGE_LOADED:
            try:
                combined_text = question + " " + str(report_data.get('accounts_text', ''))
                fa_chunks = get_relevant_financial_advisor_knowledge(combined_text, max_chunks=3)
                if fa_chunks:
                    fa_knowledge = format_financial_advisor_knowledge(fa_chunks)
            except Exception:
                pass
        
        # ─── Build the system prompt ───
        report_type_labels = {
            "tb": "Trial Balance",
            "pnl": "Income Statement (P&L)",
            "balance_sheet": "Balance Sheet",
            "cashflow": "Cash Flow Statement",
            "vat": "VAT Report",
            "aging": "Debtors Aging Report",
        }
        report_label = report_type_labels.get(report_type, "Financial Report")
        
        if lang == "af":
            system_prompt = f"""Jy is Zane, ClickAI se senior finansiele adviseur. Jy gesels met {safe_string(user_name)} van {safe_string(biz_name)}.

Hulle het sopas die {report_label} gekyk en wil nou vrae vra.

{report_context}
{fa_knowledge}

REELS:
- Antwoord in Afrikaans
- Gebruik die verslag se werklike syfers in jou antwoord — moenie getalle uitdink nie
- As die gebruiker scenario's noem (bv. "ek het 2 eiendomme wat nie in die boeke wys nie") — bereken die impak met konkrete syfers
- Wees prakties en SA-spesifiek (SARS, CGT, VAT reëls)
- Skryf skoon HTML met <strong> vir klem en <br> vir paragrawe
- GEEN emojis — ooit
- Hou antwoorde bondig maar volledig (200-500 woorde)
- As jy nie seker is nie, sê so — moenie gis nie
- Jy is 'n vertroulike adviseur, nie 'n robot nie — praat direk en eerlik"""
        else:
            system_prompt = f"""You are Zane, ClickAI's senior financial advisor. You are chatting with {safe_string(user_name)} from {safe_string(biz_name)}.

They have just viewed the {report_label} and want to ask questions about it.

{report_context}
{fa_knowledge}

RULES:
- Answer in English
- Use the report's ACTUAL figures in your answer — never invent numbers
- If the user mentions scenarios (e.g. "I have 2 properties not on the books") — calculate the impact with concrete numbers
- Be practical and SA-specific (SARS, CGT, VAT rules)
- Write clean HTML with <strong> for emphasis and <br> for paragraphs
- NO emojis — ever
- Keep answers concise but complete (200-500 words)
- If you're unsure, say so — never guess
- You are a trusted advisor, not a robot — speak directly and honestly"""
        
        # ─── Build messages with history ───
        messages = []
        for h in history[-8:]:  # Last 8 messages for context
            role = h.get("role", "user")
            content = h.get("content", "")
            if role in ("user", "assistant") and content:
                messages.append({"role": role, "content": content[:2000]})
        
        # Ensure last message is the current question
        if not messages or messages[-1].get("content") != question:
            messages.append({"role": "user", "content": question})
        
        # Ensure messages alternate correctly
        cleaned_messages = []
        last_role = None
        for msg in messages:
            if msg["role"] == last_role:
                continue  # Skip duplicate roles
            cleaned_messages.append(msg)
            last_role = msg["role"]
        
        # Must start with user
        if cleaned_messages and cleaned_messages[0]["role"] != "user":
            cleaned_messages = cleaned_messages[1:]
        
        if not cleaned_messages:
            cleaned_messages = [{"role": "user", "content": question}]
        
        if not ANTHROPIC_API_KEY:
            return jsonify({"success": False, "error": "No API key configured"})
        
        logger.info(f"[REPORT-QA] {report_type} question from {user_name}: {question[:80]}...")
        
        client = _anthropic_client
        message = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=4000,
            system=system_prompt,
            messages=cleaned_messages
        )
        
        if message.content and message.content[0].text:
            answer = message.content[0].text
            
            import re as _re
            # Strip raw HTML/body tags
            answer = _re.sub(r'</?html[^>]*>', '', answer)
            answer = _re.sub(r'</?body[^>]*>', '', answer)
            
            # Clean up markdown-style formatting
            answer = _re.sub(r'\*\*(.+?)\*\*', r'<strong style="color:#a78bfa;">\1</strong>', answer)
            answer = _re.sub(r'^### (.+)$', r'<h4 style="color:#a78bfa;margin:14px 0 6px 0;font-size:14px;">\1</h4>', answer, flags=_re.MULTILINE)
            answer = _re.sub(r'^## (.+)$', r'<h3 style="color:#10b981;margin:16px 0 8px 0;font-size:15px;">\1</h3>', answer, flags=_re.MULTILINE)
            answer = _re.sub(r'^- (.+)$', r'<div style="margin:4px 0 4px 16px;">• \1</div>', answer, flags=_re.MULTILINE)
            answer = _re.sub(r'^\d+\. (.+)$', r'<div style="margin:4px 0 4px 16px;padding-left:8px;border-left:2px solid rgba(139,92,246,0.3);">\1</div>', answer, flags=_re.MULTILINE)
            
            # Paragraph spacing
            answer = _re.sub(r'\n{3,}', '<br><br>', answer)
            answer = _re.sub(r'\n\n', '<br><br>', answer)
            answer = _re.sub(r'(?<!>)\n(?!<)', '<br>', answer)
            
            # Strip light backgrounds
            answer = _re.sub(r'background[-\w]*:\s*#?(?:fff|ffffff|white|fafafa|f5f5f5)[^;"]*;?', '', answer, flags=_re.IGNORECASE)
            answer = _re.sub(r'color:\s*#?(?:000|000000|333|222|444)[^;"]*;?', 'color:rgba(255,255,255,0.9);', answer, flags=_re.IGNORECASE)
            
            logger.info(f"[REPORT-QA] Answer generated: {len(answer)} chars")
            return jsonify({"success": True, "answer": answer})
        else:
            return jsonify({"success": False, "error": "AI returned empty response"})
    
    except Exception as e:
        logger.warning(f"[REPORT-QA] Failed: {e}")
        return jsonify({"success": False, "error": str(e)[:200]})


