# BATCH IMPORT - Receives data directly from frontend (no cache needed)
# ═══════════════════════════════════════════════════════════════════════════════

def _fix_sage_date(val):
    """Convert Sage DD/MM/YYYY → YYYY-MM-DD for Supabase. Also handles DD-MM-YYYY, YYYY/MM/DD."""
    if not val or not isinstance(val, str):
        return val
    val = val.strip()
    if not val:
        return val
    # Already ISO format
    if re.match(r'^\d{4}-\d{2}-\d{2}', val):
        return val[:10]
    # DD/MM/YYYY or DD-MM-YYYY
    m = re.match(r'^(\d{1,2})[/\-](\d{1,2})[/\-](\d{4})$', val)
    if m:
        d, mo, y = m.groups()
        return f"{y}-{mo.zfill(2)}-{d.zfill(2)}"
    # YYYY/MM/DD
    m2 = re.match(r'^(\d{4})[/\-](\d{1,2})[/\-](\d{1,2})$', val)
    if m2:
        y, mo, d = m2.groups()
        return f"{y}-{mo.zfill(2)}-{d.zfill(2)}"
    return val

@app.route("/api/smart-import/batch", methods=["POST"])
@login_required
def api_smart_import_batch():
    """Import a batch of records - data comes directly from frontend"""
    user = Auth.get_current_user()
    business = Auth.get_current_business()
    biz_id = business.get("id") if business else None
    
    if not biz_id:
        return jsonify({"success": False, "error": "No business selected"})
    
    try:
        data = request.get_json()
        data_type = data.get("data_type")
        records = data.get("records", []) or data.get("all_data", [])
        replace_mode = data.get("replace", False)  # Replace existing records instead of skipping
        
        if not records:
            return jsonify({"success": False, "error": "No records to import"})
        
        # If replace mode, clear existing data first for clean slate
        cleared = 0
        if replace_mode and data_type in ("customers", "suppliers", "stock"):
            if data_type == "stock":
                # Stock has two tables - clear both
                for tbl in ["stock_items", "stock"]:
                    existing = db.get(tbl, {"business_id": biz_id}) or []
                    for rec in existing:
                        try:
                            db.delete(tbl, rec.get("id"), biz_id)
                            cleared += 1
                        except: pass
            else:
                table = {"customers": "customers", "suppliers": "suppliers"}[data_type]
                existing = db.get(table, {"business_id": biz_id}) or []
                for rec in existing:
                    try:
                        db.delete(table, rec.get("id"), biz_id)
                        cleared += 1
                    except: pass
            logger.info(f"[SMART-IMPORT] Replace mode: cleared {cleared} existing {data_type}")
        
        results = []
        
        for row in records:
            name = ""
            status = "error"
            error_msg = ""
            
            try:
                if data_type == "customers":
                    name = str(row.get("name", "")).strip()
                    if not name:
                        status = "skipped"
                        error_msg = "No name"
                    else:
                        existing = None if replace_mode else db.get("customers", {"business_id": biz_id, "name": name})
                        if existing:
                            # Update existing record
                            exist_id = existing[0].get("id") if isinstance(existing, list) else existing.get("id")
                            code = str(row.get("account_code", row.get("code", ""))).strip()
                            # Only include fields that exist in the customers table
                            allowed_fields = {'name', 'code', 'phone', 'cell', 'fax', 'email', 'website',
                                              'address', 'vat_number', 'balance', 'credit_limit', 'active',
                                              'category', 'contact_name', 'price_list', 'sales_rep',
                                              'discount_percentage', 'vat_type', 'payment_terms', 'notes'}
                            exclude_fields = {'account_code', 'business_id', 'id'}
                            updates = {k: v for k, v in row.items() if k in allowed_fields and v}
                            updates["name"] = name
                            if code: updates["code"] = code
                            success = db.update("customers", exist_id, updates)
                            status = "updated" if success else "error"
                            if not success: error_msg = "Update failed"
                        else:
                            # Pass ALL row data to RecordFactory - exclude fields we pass explicitly
                            code = str(row.get("account_code", row.get("code", ""))).strip()
                            exclude_fields = {'name', 'account_code', 'code', 'business_id'}
                            extra_kwargs = {k: v for k, v in row.items() if k not in exclude_fields}
                            record = RecordFactory.customer(
                                business_id=biz_id,
                                name=name,
                                code=code,
                                **extra_kwargs
                            )
                            result = db.save("customers", record)
                            success = result[0] if isinstance(result, tuple) else result
                            resp = result[1] if isinstance(result, tuple) else ""
                            if success:
                                status = "imported"
                            else:
                                status = "error"
                                error_msg = str(resp)[:50]
                
                elif data_type == "suppliers":
                    name = str(row.get("name", "")).strip()
                    if not name:
                        status = "skipped"
                    else:
                        existing = None if replace_mode else db.get("suppliers", {"business_id": biz_id, "name": name})
                        if existing:
                            exist_id = existing[0].get("id") if isinstance(existing, list) else existing.get("id")
                            code = str(row.get("account_code", row.get("code", ""))).strip()
                            # Only include fields that exist in the suppliers table
                            allowed_fields = {'name', 'code', 'phone', 'cell', 'fax', 'email', 'website',
                                              'address', 'vat_number', 'balance', 'credit_limit', 'active',
                                              'category', 'contact_name', 'discount_percentage', 'vat_type',
                                              'payment_terms', 'notes'}
                            updates = {k: v for k, v in row.items() if k in allowed_fields and v}
                            updates["name"] = name
                            if code: updates["code"] = code
                            success = db.update("suppliers", exist_id, updates)
                            status = "updated" if success else "error"
                            if not success: error_msg = "Update failed"
                        else:
                            # Pass ALL row data to RecordFactory - exclude fields we pass explicitly
                            code = str(row.get("account_code", row.get("code", ""))).strip()
                            exclude_fields = {'name', 'account_code', 'code', 'business_id'}
                            extra_kwargs = {k: v for k, v in row.items() if k not in exclude_fields}
                            record = RecordFactory.supplier(
                                business_id=biz_id,
                                name=name,
                                code=code,
                                **extra_kwargs
                            )
                            result = db.save("suppliers", record)
                            success = result[0] if isinstance(result, tuple) else result
                            resp = result[1] if isinstance(result, tuple) else ""
                            if success:
                                status = "imported"
                            else:
                                status = "error"
                                error_msg = str(resp)[:50]
                
                elif data_type == "stock":
                    name = str(row.get("description", row.get("code", ""))).strip()
                    code = str(row.get("code", "")).strip()
                    if not name and not code:
                        status = "skipped"
                    else:
                        # Pass ALL row data to RecordFactory - exclude fields we pass explicitly
                        exclude_fields = {'description', 'business_id'}
                        extra_kwargs = {k: v for k, v in row.items() if k not in exclude_fields}
                        record = RecordFactory.stock_item(
                            business_id=biz_id,
                            description=name or code,
                            **extra_kwargs
                        )
                        result = db.save_stock(record)
                        success = result[0] if isinstance(result, tuple) else result
                        resp = result[1] if isinstance(result, tuple) else ""
                        if success:
                            status = "imported"
                        else:
                            status = "error"
                            error_msg = str(resp)[:50]
                
                elif data_type == "chart_of_accounts":
                    name = str(row.get("account_name", "")).strip()
                    if not name:
                        status = "skipped"
                    else:
                        # Sage TB: account_name already split from "3200/000 : Bank Charges"
                        acct_code = str(row.get("account_code", "")).strip()
                        acct_type = str(row.get("account_type", "expense")).strip().lower()
                        
                        # Calculate opening balance from debit/credit
                        debit = float(row.get("debit", 0) or 0)
                        credit = float(row.get("credit", 0) or 0)
                        opening_balance = debit - credit  # Positive = debit balance, Negative = credit balance
                        
                        # Check if account already exists (by code or name)
                        existing = None
                        if acct_code:
                            existing = db.get("chart_of_accounts", {"business_id": biz_id, "account_code": acct_code})
                        if not existing:
                            existing = db.get("chart_of_accounts", {"business_id": biz_id, "account_name": name})
                        
                        if existing:
                            status = "skipped"
                            error_msg = "Already exists"
                        else:
                            record = {
                                "id": generate_id(),
                                "business_id": biz_id,
                                "account_name": name,
                                "account_code": acct_code,
                                "account_type": acct_type,
                                "category": str(row.get("category", "")).strip(),
                                "opening_balance": opening_balance,
                                "debit": debit,
                                "credit": credit,
                                "is_active": True,
                                "created_at": now()
                            }
                            result = db.save("chart_of_accounts", record)
                            success = result[0] if isinstance(result, tuple) else result
                            resp = result[1] if isinstance(result, tuple) else ""
                            if success:
                                status = "imported"
                            else:
                                status = "error"
                                error_msg = str(resp)[:50]
                
                elif data_type == "supplier_invoices":
                    # Sage Supplier Invoices - import as bills/purchases
                    # Normalize Sage One column names → expected names
                    supplier_raw = str(row.get("supplier", "") or row.get("supplier_name", "") or row.get("Supplier Name", "") or row.get("supplier name", "")).strip()
                    supplier_code = ""
                    supplier_name = supplier_raw
                    # Sage format: "EPR001 : ELECT PROTECT RESPONSE (PTY) LTD"
                    if " : " in supplier_raw:
                        parts = supplier_raw.split(" : ", 1)
                        supplier_code = parts[0].strip()
                        supplier_name = parts[1].strip()
                    
                    name = supplier_name
                    doc_no = str(row.get("document_no", "") or row.get("doc_no", "") or row.get("Doc. No.", "") or row.get("doc. no.", "") or row.get("Doc No", "")).strip()
                    supplier_inv = str(row.get("supplier_inv_no", "") or row.get("supp_inv", "") or row.get("Supp. Inv.", "") or row.get("supp. inv.", "") or row.get("Supp Inv", "")).strip()
                    cust_ref = str(row.get("cust_ref", "") or row.get("Cust. Ref.", "") or row.get("cust. ref.", "") or row.get("reference", "")).strip()
                    
                    # Amount fields - try multiple Sage column names
                    outstanding = 0
                    for amt_key in ["outstanding", "amount_due", "Amount Due", "amount due", "Amount_Due", "balance"]:
                        val = row.get(amt_key, None)
                        if val is not None:
                            try: outstanding = float(str(val).replace('R', '').replace('r', '').replace(',', '').replace(' ', '').strip() or '0')
                            except: outstanding = 0
                            break
                    
                    total = 0
                    for tot_key in ["total", "Total", "amount", "Amount", "amount_incl"]:
                        val = row.get(tot_key, None)
                        if val is not None:
                            try: total = float(str(val).replace('R', '').replace('r', '').replace(',', '').replace(' ', '').strip() or '0')
                            except: total = 0
                            break
                    
                    # Sage status mapping
                    sage_status = str(row.get("status", "") or row.get("Status", "")).strip().lower()
                    if sage_status in ("paid", "betaal"):
                        inv_status = "paid"
                    elif sage_status in ("overdue", "agterstallig"):
                        inv_status = "overdue"
                    else:
                        inv_status = "outstanding" if outstanding > 0 else "paid"
                    
                    date_val = _fix_sage_date(str(row.get("date", "") or row.get("Date", "")).strip())
                    due_date_val = _fix_sage_date(str(row.get("due_date", "") or row.get("Due Date", "") or row.get("due date", "")).strip())
                    
                    if not supplier_name or supplier_name.lower().startswith("grand total"):
                        status = "skipped"
                        error_msg = "Skip row"
                    else:
                        # Look up supplier
                        existing_supplier = db.get("suppliers", {"business_id": biz_id, "name": supplier_name})
                        sup_id = ""
                        if existing_supplier:
                            sup_id = existing_supplier[0].get("id") if isinstance(existing_supplier, list) else existing_supplier.get("id")
                        
                        # Back-calculate VAT from inclusive total (Sage doesn't give separate VAT)
                        si_subtotal = (total or outstanding) / 1.15
                        si_vat = (total or outstanding) - si_subtotal
                        
                        record = RecordFactory.supplier_invoice(
                            business_id=biz_id,
                            supplier_id=sup_id,
                            supplier_name=supplier_name,
                            invoice_number=supplier_inv or doc_no,
                            date=date_val or now()[:10],
                            due_date=due_date_val,
                            subtotal=round(si_subtotal, 2),
                            vat=round(si_vat, 2),
                            total=total or outstanding,
                            status=inv_status,
                            notes=f"Sage import - Ref: {cust_ref}" if cust_ref else "Sage import"
                        )
                        result = db.save("supplier_invoices", record)
                        success = result[0] if isinstance(result, tuple) else result
                        resp = result[1] if isinstance(result, tuple) else ""
                        if success:
                            status = "imported"
                        else:
                            status = "error"
                            error_msg = str(resp)[:50]
                
                elif data_type == "customer_invoices":
                    # Sage Customer Invoices - import as sales invoices
                    customer_raw = str(row.get("customer", "") or row.get("customer_name", "") or row.get("Customer Name", "")).strip()
                    customer_code = ""
                    customer_name = customer_raw
                    if " : " in customer_raw:
                        parts = customer_raw.split(" : ", 1)
                        customer_code = parts[0].strip()
                        customer_name = parts[1].strip()
                    
                    name = customer_name
                    doc_no = str(row.get("document_no", "") or row.get("Document Number", "")).strip()
                    cust_ref = str(row.get("customer_ref", "") or row.get("customer_inv_no", "") or row.get("Customer Ref.", "")).strip()
                    
                    # Amount fields
                    outstanding = 0
                    for amt_key in ["outstanding", "amount_due", "Amount Due", "balance"]:
                        val = row.get(amt_key, None)
                        if val is not None:
                            try: outstanding = float(str(val).replace('R', '').replace('r', '').replace(',', '').replace(' ', '').strip() or '0')
                            except: outstanding = 0
                            break
                    
                    total = 0
                    for tot_key in ["total", "Total", "amount", "amount_incl"]:
                        val = row.get(tot_key, None)
                        if val is not None:
                            try: total = float(str(val).replace('R', '').replace('r', '').replace(',', '').replace(' ', '').strip() or '0')
                            except: total = 0
                            break
                    
                    # Status mapping
                    sage_status = str(row.get("status", "") or row.get("Status", "")).strip().lower()
                    if sage_status in ("paid", "betaal"):
                        inv_status = "paid"
                    elif sage_status in ("overdue", "agterstallig"):
                        inv_status = "overdue"
                    elif sage_status in ("unpaid",):
                        inv_status = "outstanding"
                    else:
                        inv_status = "outstanding" if outstanding > 0 else "paid"
                    
                    date_val = _fix_sage_date(str(row.get("date", "") or row.get("Date", "")).strip())
                    due_date_val = _fix_sage_date(str(row.get("due_date", "") or row.get("Due Date", "")).strip())
                    
                    if not customer_name or customer_name.lower().startswith("grand total"):
                        status = "skipped"
                        error_msg = "Skip row"
                    else:
                        # Look up customer
                        existing_customer = db.get("customers", {"business_id": biz_id, "name": customer_name})
                        cust_id = ""
                        if existing_customer:
                            cust_id = existing_customer[0].get("id") if isinstance(existing_customer, list) else existing_customer.get("id")
                        
                        # Use exclusive (subtotal) and vat from Sage if available
                        exclusive = 0
                        for ex_key in ["exclusive", "subtotal", "Exclusive"]:
                            val = row.get(ex_key, None)
                            if val is not None:
                                try: exclusive = float(str(val).replace('R', '').replace('r', '').replace(',', '').replace(' ', '').strip() or '0')
                                except: exclusive = 0
                                break
                        
                        vat_amt = 0
                        for vat_key in ["vat", "VAT", "tax"]:
                            val = row.get(vat_key, None)
                            if val is not None:
                                try: vat_amt = float(str(val).replace('R', '').replace('r', '').replace(',', '').replace(' ', '').strip() or '0')
                                except: vat_amt = 0
                                break
                        
                        record = RecordFactory.invoice(
                            business_id=biz_id,
                            customer_id=cust_id,
                            customer_name=customer_name,
                            items=[],
                            invoice_number=doc_no,
                            date=date_val or now()[:10],
                            due_date=due_date_val,
                            subtotal=exclusive or total or outstanding,
                            vat=vat_amt,
                            total=total or outstanding,
                            status=inv_status,
                            notes=f"Sage import - Ref: {cust_ref}" if cust_ref else "Sage import"
                        )
                        result = db.save("invoices", record)
                        success = result[0] if isinstance(result, tuple) else result
                        resp = result[1] if isinstance(result, tuple) else ""
                        if success:
                            status = "imported"
                        else:
                            status = "error"
                            error_msg = str(resp)[:50]
                
                elif data_type == "transactions":
                    name = str(row.get("description", row.get("reference", "Transaction"))).strip()[:50]
                    record = {
                        "id": generate_id(),
                        "business_id": biz_id,
                        "date": _fix_sage_date(str(row.get("date", "")).strip()),
                        "account_code": str(row.get("account_code", "")).strip(),
                        "account_name": str(row.get("account_name", "")).strip(),
                        "reference": str(row.get("reference", "")).strip(),
                        "description": str(row.get("description", "")).strip(),
                        "debit": float(row.get("debit", 0) or 0),
                        "credit": float(row.get("credit", 0) or 0),
                        "created_at": now()
                    }
                    result = db.save("gl_transactions", record)
                    success = result[0] if isinstance(result, tuple) else result
                    resp = result[1] if isinstance(result, tuple) else ""
                    if success:
                        status = "imported"
                    else:
                        status = "error"
                        error_msg = str(resp)[:50]
                
                else:
                    status = "error"
                    error_msg = f"Unknown type: {data_type}"
                    
            except Exception as e:
                status = "error"
                error_msg = str(e)[:50]
                logger.error(f"[SMART-IMPORT] Batch error: {e}")
            
            results.append({
                "name": name or "Record",
                "status": status,
                "error": error_msg
            })
        
        imported_count = sum(1 for r in results if r.get("status") in ("imported", "updated"))
        updated_count = sum(1 for r in results if r.get("status") == "updated")
        new_count = sum(1 for r in results if r.get("status") == "imported")
        return jsonify({"success": True, "results": results, "imported": imported_count, "total_imported": imported_count,
                        "new_records": new_count, "updated_records": updated_count, "cleared": cleared if replace_mode else 0})
        
    except Exception as e:
        import traceback
        tb = traceback.format_exc()
        logger.error(f"[SMART-IMPORT] Batch endpoint error: {e}\nTraceback:\n{tb}")
        return jsonify({"success": False, "error": f"Batch error: {str(e)[:200]}"})


# ═══════════════════════════════════════════════════════════════════════════════
# STREAMING IMPORT - Shows real-time progress (LEGACY - uses cache)
# ═══════════════════════════════════════════════════════════════════════════════

@app.route("/api/smart-import/stream")
@login_required
def api_smart_import_stream():
    """Stream import progress using Server-Sent Events"""
    from flask import Response
    
    user = Auth.get_current_user()
    business = Auth.get_current_business()
    biz_id = business.get("id") if business else None
    
    analysis_id = request.args.get("analysis_id")
    
    if not biz_id or not analysis_id or analysis_id not in _smart_import_cache:
        def error_stream():
            yield f"data: {json.dumps({'type': 'error', 'error': 'Invalid session'})}\n\n"
        return Response(error_stream(), mimetype='text/event-stream')
    
    analysis = _smart_import_cache[analysis_id]
    
    if analysis.get("business_id") != biz_id:
        def error_stream():
            yield f"data: {json.dumps({'type': 'error', 'error': 'Access denied'})}\n\n"
        return Response(error_stream(), mimetype='text/event-stream')
    
    def generate():
        imported = {}
        current = 0
        
        for dataset in analysis.get("datasets", []):
            data_type = dataset.get("type")
            all_data = dataset.get("all_data", [])
            total = len(all_data)
            
            if not all_data:
                continue
            
            # Send start event
            yield f"data: {json.dumps({'type': 'start', 'total': total, 'data_type': data_type})}\n\n"
            
            count = 0
            
            for row in all_data:
                current += 1
                name = ""
                status = "error"
                error_msg = ""
                
                try:
                    if data_type == "customers":
                        name = str(row.get("name", "")).strip()
                        if not name:
                            status = "skipped"
                        else:
                            existing = db.get("customers", {"business_id": biz_id, "name": name})
                            if existing:
                                status = "skipped"
                            else:
                                record = {
                                    "business_id": biz_id,
                                    "name": name,
                                    "email": str(row.get("email", "")).strip(),
                                    "phone": str(row.get("phone", "")).strip(),
                                    "contact_name": str(row.get("contact_name", "")).strip(),
                                    "address": str(row.get("address", "")).strip(),
                                    "vat_number": str(row.get("vat_number", "")).strip(),
                                    "account_code": str(row.get("account_code", "")).strip(),
                                    "balance": float(row.get("balance", 0) or 0),
                                    "credit_limit": float(row.get("credit_limit", 0) or 0),
                                    "source": "smart_import"
                                }
                                success, _ = db.save("customers", record)
                                if success:
                                    status = "imported"
                                    count += 1
                                else:
                                    status = "error"
                                    error_msg = "DB save failed"
                    
                    elif data_type == "suppliers":
                        name = str(row.get("name", "")).strip()
                        if not name:
                            status = "skipped"
                        else:
                            existing = db.get("suppliers", {"business_id": biz_id, "name": name})
                            if existing:
                                status = "skipped"
                            else:
                                record = {
                                    "business_id": biz_id,
                                    "name": name,
                                    "email": str(row.get("email", "")).strip(),
                                    "phone": str(row.get("phone", "")).strip(),
                                    "contact_name": str(row.get("contact_name", "")).strip(),
                                    "address": str(row.get("address", "")).strip(),
                                    "vat_number": str(row.get("vat_number", "")).strip(),
                                    "account_code": str(row.get("account_code", "")).strip(),
                                    "balance": float(row.get("balance", 0) or 0),
                                    "source": "smart_import"
                                }
                                success, _ = db.save("suppliers", record)
                                if success:
                                    status = "imported"
                                    count += 1
                                else:
                                    status = "error"
                                    error_msg = "DB save failed"
                    
                    elif data_type == "stock":
                        name = str(row.get("description", row.get("code", ""))).strip()
                        code = str(row.get("code", "")).strip()
                        if not name and not code:
                            status = "skipped"
                        else:
                            if code:
                                existing = db.get_all_stock(biz_id)
                                if existing and any(s.get("code") == code for s in existing):
                                    status = "skipped"
                                    name = code
                                else:
                                    record = {
                                        "business_id": biz_id,
                                        "description": name or code,
                                        "code": code,
                                        "cost_price": float(row.get("cost_price", 0) or 0),
                                        "selling_price": float(row.get("selling_price", 0) or 0),
                                        "qty": float(row.get("qty", row.get("quantity", 0)) or 0),
                                        "quantity": float(row.get("qty", row.get("quantity", 0)) or 0),
                                        "category": str(row.get("category", "")).strip(),
                                        "unit": str(row.get("unit", "each")).strip() or "each",
                                        "source": "smart_import"
                                    }
                                    success, _ = db.save_stock(record)
                                    if success:
                                        status = "imported"
                                        count += 1
                                    else:
                                        status = "error"
                                        error_msg = "DB save failed"
                            else:
                                record = {
                                    "business_id": biz_id,
                                    "description": name,
                                    "code": "",
                                    "cost_price": float(row.get("cost_price", 0) or 0),
                                    "selling_price": float(row.get("selling_price", 0) or 0),
                                    "qty": float(row.get("qty", row.get("quantity", 0)) or 0),
                                    "source": "smart_import"
                                }
                                success, _ = db.save_stock(record)
                                if success:
                                    status = "imported"
                                    count += 1
                    
                    elif data_type == "chart_of_accounts":
                        name = str(row.get("account_name", "")).strip()
                        if not name:
                            status = "skipped"
                        else:
                            record = {
                                "business_id": biz_id,
                                "account_name": name,
                                "account_code": str(row.get("account_code", "")).strip(),
                                "account_type": str(row.get("account_type", "expense")).strip().lower(),
                                "is_active": True,
                                "source": "smart_import"
                            }
                            success, _ = db.save("chart_of_accounts", record)
                            if success:
                                status = "imported"
                                count += 1
                    
                    elif data_type == "transactions":
                        name = str(row.get("description", row.get("reference", "Transaction"))).strip()[:50]
                        record = {
                            "business_id": biz_id,
                            "date": str(row.get("date", "")).strip(),
                            "account_code": str(row.get("account_code", "")).strip(),
                            "account_name": str(row.get("account_name", "")).strip(),
                            "reference": str(row.get("reference", "")).strip(),
                            "description": str(row.get("description", "")).strip(),
                            "debit": float(row.get("debit", 0) or 0),
                            "credit": float(row.get("credit", 0) or 0),
                            "source": "smart_import"
                        }
                        success, _ = db.save("gl_transactions", record)
                        if success:
                            status = "imported"
                            count += 1
                    
                except Exception as e:
                    status = "error"
                    error_msg = str(e)[:50]
                    logger.error(f"[SMART-IMPORT] Error: {e}")
                
                # Send progress event
                yield f"data: {json.dumps({'type': 'progress', 'current': current, 'total': total, 'name': name or f'Record {current}', 'status': status, 'error': error_msg})}\n\n"
            
            imported[dataset.get("type_label", data_type.title())] = count
        
        # Clean up cache
        try:
            del _smart_import_cache[analysis_id]
        except:
            pass
        
        # Send done event
        yield f"data: {json.dumps({'type': 'done', 'imported': imported})}\n\n"
    
    return Response(generate(), mimetype='text/event-stream', headers={
        'Cache-Control': 'no-cache',
        'X-Accel-Buffering': 'no'
    })


# ═══════════════════════════════════════════════════════════════════════════════
# EXECUTE THE IMPORT (kept for backwards compatibility)
# ═══════════════════════════════════════════════════════════════════════════════

@app.route("/api/smart-import/execute", methods=["POST"])
@login_required
def api_smart_import_execute():
    """Execute the import based on Opus analysis."""
    user = Auth.get_current_user()
    business = Auth.get_current_business()
    biz_id = business.get("id") if business else None
    
    if not biz_id:
        return jsonify({"success": False, "error": "No business selected"})
    
    try:
        data = request.get_json()
        analysis_id = data.get("analysis_id")
        
        if not analysis_id or analysis_id not in _smart_import_cache:
            return jsonify({"success": False, "error": "Analysis expired. Please upload the file again."})
        
        analysis = _smart_import_cache[analysis_id]
        
        if analysis.get("business_id") != biz_id:
            return jsonify({"success": False, "error": "Access denied"})
        
        imported = {}
        
        for dataset in analysis.get("datasets", []):
            data_type = dataset.get("type")
            all_data = dataset.get("all_data", [])
            
            if not all_data:
                continue
            
            count = 0
            
            if data_type == "customers":
                for row in all_data:
                    try:
                        name = str(row.get("name", "")).strip()
                        if not name:
                            continue
                        existing = db.get("customers", {"business_id": biz_id, "name": name})
                        if existing:
                            continue
                        record = {
                            "business_id": biz_id,
                            "name": name,
                            "email": str(row.get("email", "")).strip(),
                            "phone": str(row.get("phone", "")).strip(),
                            "contact_name": str(row.get("contact_name", "")).strip(),
                            "address": str(row.get("address", "")).strip(),
                            "vat_number": str(row.get("vat_number", "")).strip(),
                            "account_code": str(row.get("account_code", "")).strip(),
                            "balance": float(row.get("balance", 0) or 0),
                            "credit_limit": float(row.get("credit_limit", 0) or 0),
                            "source": "smart_import"
                        }
                        success, _ = db.save("customers", record)
                        if success:
                            count += 1
                    except Exception as e:
                        logger.error(f"[SMART-IMPORT] Customer error: {e}")
                imported["Customers"] = count
                
            elif data_type == "suppliers":
                for row in all_data:
                    try:
                        name = str(row.get("name", "")).strip()
                        if not name:
                            continue
                        existing = db.get("suppliers", {"business_id": biz_id, "name": name})
                        if existing:
                            continue
                        record = {
                            "business_id": biz_id,
                            "name": name,
                            "email": str(row.get("email", "")).strip(),
                            "phone": str(row.get("phone", "")).strip(),
                            "contact_name": str(row.get("contact_name", "")).strip(),
                            "address": str(row.get("address", "")).strip(),
                            "vat_number": str(row.get("vat_number", "")).strip(),
                            "account_code": str(row.get("account_code", "")).strip(),
                            "balance": float(row.get("balance", 0) or 0),
                            "source": "smart_import"
                        }
                        success, _ = db.save("suppliers", record)
                        if success:
                            count += 1
                    except Exception as e:
                        logger.error(f"[SMART-IMPORT] Supplier error: {e}")
                imported["Suppliers"] = count
                
            elif data_type == "stock":
                for row in all_data:
                    try:
                        desc = str(row.get("description", "")).strip()
                        code = str(row.get("code", "")).strip()
                        if not desc and not code:
                            continue
                        if code:
                            existing = db.get_all_stock(biz_id)
                            if existing and any(s.get("code") == code for s in existing):
                                continue
                        record = {
                            "business_id": biz_id,
                            "description": desc or code,
                            "code": code,
                            "cost_price": float(row.get("cost_price", 0) or 0),
                            "selling_price": float(row.get("selling_price", 0) or 0),
                            "qty": float(row.get("qty", row.get("quantity", 0)) or 0),
                            "quantity": float(row.get("qty", row.get("quantity", 0)) or 0),
                            "category": str(row.get("category", "")).strip(),
                            "unit": str(row.get("unit", "each")).strip() or "each",
                            "source": "smart_import"
                        }
                        success, _ = db.save_stock(record)
                        if success:
                            count += 1
                    except Exception as e:
                        logger.error(f"[SMART-IMPORT] Stock error: {e}")
                imported["Stock Items"] = count
                
            elif data_type == "chart_of_accounts":
                for row in all_data:
                    try:
                        name = str(row.get("account_name", "")).strip()
                        if not name:
                            continue
                        record = {
                            "business_id": biz_id,
                            "account_name": name,
                            "account_code": str(row.get("account_code", "")).strip(),
                            "account_type": str(row.get("account_type", "expense")).strip().lower(),
                            "description": str(row.get("description", "")).strip(),
                            "is_active": True,
                            "source": "smart_import"
                        }
                        success, _ = db.save("chart_of_accounts", record)
                        if success:
                            count += 1
                    except Exception as e:
                        logger.error(f"[SMART-IMPORT] Account error: {e}")
                imported["Accounts"] = count
                
            elif data_type == "transactions":
                for row in all_data:
                    try:
                        record = {
                            "business_id": biz_id,
                            "date": str(row.get("date", "")).strip(),
                            "account_code": str(row.get("account_code", "")).strip(),
                            "account_name": str(row.get("account_name", "")).strip(),
                            "reference": str(row.get("reference", "")).strip(),
                            "description": str(row.get("description", "")).strip(),
                            "debit": float(row.get("debit", 0) or 0),
                            "credit": float(row.get("credit", 0) or 0),
                            "source": "smart_import"
                        }
                        success, _ = db.save("gl_transactions", record)
                        if success:
                            count += 1
                    except Exception as e:
                        logger.error(f"[SMART-IMPORT] Transaction error: {e}")
                imported["Transactions"] = count
        
        del _smart_import_cache[analysis_id]
        
        try:
            db.save("audit_log", {
                "id": generate_id(),
                "user_id": user.get("id"),
                "business_id": biz_id,
                "action": "SMART_IMPORT",
                "table_name": "multiple",
                "details": json.dumps(imported),
                "timestamp": now()
            })
        except:
            pass
        
        logger.info(f"[SMART-IMPORT] Complete for business {biz_id}: {imported}")
        
        return jsonify({"success": True, "imported": imported})
        
    except Exception as e:
        logger.error(f"[SMART-IMPORT] Execute error: {e}")
        return jsonify({"success": False, "error": str(e)})


# ═══════════════════════════════════════════════════════════════════════════════
# END SMART IMPORT MODULE
# ═══════════════════════════════════════════════════════════════════════════════


# ═══════════════════════════════════════════════════════════════════════════════
# DEDUP ENGINE - Remove duplicates across all tables
# ═══════════════════════════════════════════════════════════════════════════════

@app.route("/api/dedup/scan", methods=["POST"])
@login_required
def api_dedup_scan():
    """Scan all tables for duplicates - returns counts without deleting"""
    user = Auth.get_current_user()
    business = Auth.get_current_business()
    biz_id = business.get("id") if business else None
    if not biz_id:
        return jsonify({"success": False, "error": "No business selected"})
    
    try:
        data = request.get_json() or {}
        execute = data.get("execute", False)
        
        tables_config = {
            "customers": {"key_fields": ["name"], "table": "customers"},
            "suppliers": {"key_fields": ["name"], "table": "suppliers"},
            "stock_items": {"key_fields": ["description"], "fallback": ["code"], "table": "stock_items"},
            "invoices": {"key_fields": ["invoice_number"], "table": "invoices"},
            "supplier_invoices": {"key_fields": ["invoice_number", "supplier_name"], "table": "supplier_invoices"},
            "chart_of_accounts": {"key_fields": ["account_code"], "fallback": ["account_name"], "table": "chart_of_accounts"},
            "gl_transactions": {"key_fields": ["date", "account_code", "reference", "debit", "credit"], "table": "gl_transactions"},
            "journal_entries": {"key_fields": ["date", "account_code", "reference", "debit", "credit"], "table": "journal_entries"},
        }
        
        results = {}
        total_dupes = 0
        total_deleted = 0
        
        for label, config in tables_config.items():
            table = config["table"]
            try:
                records = db.get(table, {"business_id": biz_id}) or []
            except:
                results[label] = {"total": 0, "dupes": 0, "deleted": 0}
                continue
            
            if not records:
                results[label] = {"total": 0, "dupes": 0, "deleted": 0}
                continue
            
            # Build dedup key
            def make_key(r, fields, fallback=None):
                parts = []
                for f in fields:
                    val = str(r.get(f, "") or "").lower().strip()
                    parts.append(val)
                key = "|".join(parts)
                if not key.replace("|", ""):
                    if fallback:
                        parts2 = []
                        for f in fallback:
                            val = str(r.get(f, "") or "").lower().strip()
                            parts2.append(val)
                        key = "|".join(parts2)
                return key if key.replace("|", "") else None
            
            # Sort newest first - keep newest (most recently imported = most accurate)
            sorted_recs = sorted(records, key=lambda x: x.get("created_at", "") or "", reverse=True)
            seen = {}
            dupes = []
            
            for r in sorted_recs:
                key = make_key(r, config["key_fields"], config.get("fallback"))
                if not key:
                    continue
                if key in seen:
                    dupes.append(r)
                else:
                    seen[key] = r
            
            deleted = 0
            if execute and dupes:
                dup_ids = [d.get("id") for d in dupes if d.get("id")]
                if dup_ids:
                    success_count, fail_count = db.delete_many(table, dup_ids, biz_id)
                    deleted = success_count
                    logger.info(f"[DEDUP] {table}: deleted {deleted}/{len(dup_ids)} duplicates")
            
            results[label] = {"total": len(records), "dupes": len(dupes), "deleted": deleted}
            total_dupes += len(dupes)
            total_deleted += deleted
        
        return jsonify({
            "success": True,
            "results": results,
            "total_dupes": total_dupes,
            "total_deleted": total_deleted,
            "executed": execute
        })
    except Exception as e:
        logger.error(f"[DEDUP] Error: {e}")
        return jsonify({"success": False, "error": str(e)})


